INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('gado ou ao assessor económico externo do visado e estritamente para efeitos do exercício de defesa nos termos do n.º 1 do artigo 25.º e da impugnação judicial da decisão da Autoridade da Concorrência, não sendo permitida a sua reprodução, total ou parcial por qualquer meio, nem a sua utilização para qualquer outro fim, sem prejuízo do disposto no n.º 7 do artigo 12.º, e nos artigos 14.º e 16.º da Lei n.º 23/2018, de 5 de junho.
