INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('pias ou certidões do processo ou de partes deste a pedido do arguido, ainda que em suporte digital, acresce aos valores referidos nos números anteriores uma quantia calculada nos termos previstos nos mesmos números em função do número de folhas disponibilizadas.
